import scala.collection.mutable

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val ans = new Array[Long](queries.length)
  for (i <- queries.indices) {
    val l = queries(i)(0).toInt
    val r = queries(i)(1).toInt
    val threshold = queries(i)(2)
    val subArray = nums.slice(l, r + 1)
    val freq = mutable.HashMap[Long, Long]()
    subArray.foreach { num =>
      freq(num) = freq.getOrElse(num, 0L) + 1L
    }
    val candidates = freq.filter { case (_, cnt) => cnt >= threshold }
    if (candidates.isEmpty) {
      ans(i) = -1L
    } else {
      val maxFreq = candidates.values.max
      val filtered = candidates.filter { case (_, cnt) => cnt == maxFreq }
      ans(i) = filtered.keys.min
    }
  }
  ans
}
